import React from "react";
import { Drawer, List, ListItem, ListItemText, Box } from "@mui/material";
import { Link, useLocation } from "react-router-dom";

const Sidebar = () => {
  const location = useLocation();

  const menuItems = [
    { label: "Dashboard", path: "/" },
    { label: "Hospitals", path: "/hospitals" },
    { label: "Model Metrics", path: "/model-metrics" },
    { label: "Federated Learning", path: "/federated-learning" },
    { label: "Blockchain Logs", path: "/blockchain-logs" },
    { label: "Security Alerts", path: "/security-alerts" }
  ];

  return (
    <Drawer variant="permanent" anchor="left">
      <Box sx={{ width: 220 }}>
        <Box sx={{ p: 2, background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)", color: "white" }}>
          <h3 style={{ margin: 0 }}>Healthcare AI</h3>
        </Box>
        <List>
          {menuItems.map((item) => (
            <ListItem
              button
              key={item.path}
              component={Link}
              to={item.path}
              sx={{
                background: location.pathname === item.path ? "#e3f2fd" : "transparent",
                borderLeft: location.pathname === item.path ? "4px solid #2196F3" : "4px solid transparent",
                color: location.pathname === item.path ? "#2196F3" : "inherit",
                fontWeight: location.pathname === item.path ? "bold" : "normal",
                paddingLeft: "12px !important",
                transition: "all 0.3s ease",
                "&:hover": {
                  background: "#f5f5f5"
                }
              }}
            >
              <ListItemText primary={item.label} />
            </ListItem>
          ))}
        </List>
      </Box>
    </Drawer>
  );
};

export default Sidebar;
